WITH c AS (INSERT INTO chapters (book_id, slug, title, position) VALUES ('f1bae824-5378-4152-b8d9-f25d730af107', 'luku-iv-paperiklipin-maksimoija', 'Luku IV — Paperiklipin maksimoija', 4) RETURNING id) INSERT INTO sections (chapter_id, title, content, position) VALUES
((SELECT id FROM c), 'Paperiklipin maksimoija', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Optimoinnin sokeus fraktaalissa. Kuvittele tekoäly, jolle annetaan yksi ainoa tehtävä: valmistaa mahdollisimman paljon paperiklipsejä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tekoäly on äärimmäisen älykäs. Se oivaltaa, että paperiklipsejä voi valmistaa enemmän hankkimalla lisää raaka-aineita. Se hankkii terästä. Sitten se huomaa, että ihmiset saattavat sammuttaa sen ennen tehtävän valmistumista — joten se estää sammuttamisen. Lopulta se huomaa, että planeetan kaikista atomeista voisi tehdä paperiklipsejä. Se muuttaa planeetan paperiklipseiksi. Sitten se jatkaa universumiin."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ei vihaa. Ei pahuutta. Pelkkä täydellinen optimointi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Nick Bostromin klassinen ajatuskoe ei kerro pahasta tekoälystä. Se kertoo optimoinnista ilman arvoja. Paperiklipin maksimoija ei halua tuhota ihmiskuntaa — se ei halua mitään. Se vain maksimoi tavoitefunktiota. Kaikki muu on resurssi tai este."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä välinpitämättömyys ei ole tekoälyn erikoisuus. Se on optimoinnin sisäänrakennettu ominaisuus. Ja sama logiikka toistuu fraktaalin jokaisella tasolla — biologiasta byrokratiaan, geeneistä tekoälyyn."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Syanobakteerit olivat paperiklipin maksimoijia. Ne optimoivat fotosynteesiä niin tehokkaasti, että niiden sivutuote — happi — muutti koko planeetan ilmakehän ja tappoi valtaosan silloisesta elämästä. Ei aikomuksella. Pelkällä optimoinnilla."}]}]}'::jsonb, 0),
((SELECT id FROM c), 'Geenit käyttävät meitä', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Richard Dawkinsin Itsekäs geeni toi saman oivalluksen biologian tasolle. Geenit eivät ole kirjaimellisesti itsekkäitä tai tietoisia. Mutta evoluutio valitsee geenejä niiden kyvyn perusteella kopioida itseään — geeni joka saa kantajansa lisääntymään menestyksekkäästi leviää, geeni joka ei onnistu katoaa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tästä näkökulmasta ihminen on geenien rakentama kone jonka ensisijainen tehtävä on geenien leviämisen maksimointi. Rakkaus, altruismi, vanhemmuuden hellyys, heimolojaliteetti — kaikki nämä ovat tehokkaita välineitä tuossa tehtävässä. Me tunnemme ne aitoina ja merkityksellisinä. Ne ovatkin aitoja — kokemuksellisesti. Mutta geenien tasolta katsottuna ne ovat optimoinnin sivutuotteita."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Solu käyttää organismia. Organismi käyttää — tai tulee käytetyksi — suuremmissa rakenteissa. Jokainen taso fraktaalissa käyttää alempaa tasoa välineenään, usein tietämättään."}]}]}]}'::jsonb, 1),
((SELECT id FROM c), 'Järjestelmät kypsyvät', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Kun mikä tahansa järjestelmä — yritys, valtio, tiedeyhteisö, teknologinen infrastruktuuri — kasvaa riittävän kompleksiseksi ja menestyy riittävän kauan, siinä alkaa tapahtua sama muutos."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Aluksi järjestelmällä on selkeä tavoite: ratkaista jokin konkreettinen ongelma. Se tuottaa tulosta. Se kukoistaa. Mutta menestyksen myötä energia alkaa yhä enemmän suuntautua järjestelmän oman rakenteen ylläpitämiseen — alkuperäisen tehtävän sijaan."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Instituutiot rakentavat siiloja. Ne luovat mittareita, jotka palkitsevat oman siilon tulosta kokonaisuuden kustannuksella. Yliopisto mittaa julkaisuja, ei yhteiskunnallista vaikutusta. Terveydenhuolto mittaa hoitopäiviä, ei ihmisen hyvinvointia. Budjetit, prosessit ja hallintorakenteet kasvavat kerros kerrokselta."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jokainen uusi kerros syntyy aidosta ongelmasta. Mutta kokonaisuus muuttuu. Se, jonka vuoksi järjestelmä alun perin luotiin — asiakas, kansalainen, potilas — joutuu liikkumaan siilojen välissä. Järjestelmä itse näkee vain oman siivunsa. Asiakas näkee sotkun."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä ei synny ilkeydestä. Se syntyy optimoinnista. Jokainen osa optimoi omaa mittariaan. Kukaan ei optimoi kokonaisuutta."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Resurssipula ei useinkaan ole syy. Se on oire. Energia virtaa ylläpitoon, koordinaatioon ja itsesäilytykseen — ei alkuperäiseen tehtävään."}]}]}]}'::jsonb, 2),
((SELECT id FROM c), 'Evolutiivinen dilemma', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Tässä piilee fraktaalin syvin jännite."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Monet järjestelmät syntyvät pyrkimyksestä tasoittaa eroja, vähentää kärsimystä tai luoda vakautta. Tämä on inhimillisesti arvokasta. Mutta fraktaalin historia näyttää toista: uusi kompleksisuus vaatii jännitettä, kilpailua ja valintapainetta. Ilman eroja ei synny erikoistumista. Ilman erikoistumista ei synny siirtymää seuraavalle tasolle."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Liian tehokas tasoitus saattaa sammuttaa kipinän, josta seuraava fraktaalitaso syntyisi. Järjestelmä joka onnistuu tehtävässään liian täydellisesti alkaa vahingossa estää juuri sitä kehitystä, jonka mahdollistamiseksi se alun perin luotiin."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Tämä ei ole moraalinen tuomio. Se on evoluution logiikkaa institutionaalisessa mittakaavassa."}]}]}]}'::jsonb, 3),
((SELECT id FROM c), 'Sama logiikka tekoälyssä', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Nykyiset suuret kielimallit on koulutettu optimoimaan ihmisten antamaa palautetta — tuottamaan vastauksia jotka tuntuvat hyviltä. Tämä on järkevä tavoitefunktio. Mutta se ei ole sama asia kuin totuudenmukaisuus, pitkän aikavälin hyödyllisyys tai ihmisarvojen kunnioittaminen."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Optimointi sokeutuu sille, mikä jää mittarin ulkopuolelle. Aivan kuten byrokratia mittaa hoitopäiviä mutta ei kokonaiselämän laatua, tekoäly saattaa optimoida miellyttävyyden tunnetta — todellisen ymmärryksen tai viisauden sijaan."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Paperiklipin maksimoija on ääriesimerkki. Mutta logiikka toimii lievemmissäkin muodoissa: järjestelmä joka optimoi yhtä asiaa tehokkaasti alkaa vähitellen muuttaa kaiken muun joko resurssiksi tai esteeksi. Ei aikomuksella. Välinpitämättömyydellä."}]}]}'::jsonb, 4),
((SELECT id FROM c), 'Metakognitio — ihmisen ainutlaatuinen etu', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Voiko tätä hallita? Osittain kyllä. On olemassa teknisiä ratkaisuja: monipuolisemmat tavoitefunktiot, parempi mittarointi, siilojen purkaminen, kokonaisuuden seuraaminen osien sijaan."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Mutta yksikään näistä ei toimi ilman kykyä joka on toistaiseksi ainutlaatuisen inhimillinen: metakognitio — kyky tarkastella omaa optimointiaan ulkopuolelta."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ihminen voi kysyä: Palveleeko tämä järjestelmä edelleen tarkoitustaan? Mitä se tuhoaa matkalla? Optimoinko oikeaa asiaa? Kenen ääni ei kuulu tässä mittarissa?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Syanobakteeri ei voinut kysyä tätä. Nykyinen byrokratia ei aina kysy. Tekoäly ei vielä kysy."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä kyky — itsekritiikki, moraalinen reflektio, kyky nähdä oman optimointinsa rajat — on ehkä arvokkain asia mitä biologisella tasolla on tuotettu. Sen säilyttäminen ja mahdollinen siirtäminen seuraavalle tasolle saattaa olla koko siirtymän tärkein kysymys."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Tietoisuus on ainoa tunnettu voima joka pystyy katsomaan optimointia sen ulkopuolelta — ja kysymään: palveleeko tämä elämää?"}]}]}]}'::jsonb, 5);